#include <stdio.h>
#include <stdint.h>
const long long MOD = 1000000007LL;
long long modPow(long long base, long long exp) {
    long long res = 1;
    base %= MOD;
    while (exp) {
        if (exp & 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1;
    }
    return res;
}
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int even = 0, odd = 0, x;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &x);
            if (x & 1) odd++; else even++;
        }
        long long ans = modPow(2, even);
        if (odd == 0) ans = (ans - 1 + MOD) % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

