import sys
MOD = 1000000007

def mod_pow(a, e):
    r = 1
    a %= MOD
    while e:
        if e & 1:
            r = r * a % MOD
        a = a * a % MOD
        e >>= 1
    return r

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        N = next(it)
        even = odd = 0
        for _ in range(N):
            val = next(it)
            if val & 1:
                odd += 1
            else:
                even += 1
        ans = mod_pow(2, even)
        if odd == 0:
            ans = (ans - 1) % MOD
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

